{:version=>3, :sections=>[{:offset=>{:line=>0, :column=>0}, :map=>{:version=>3, :sourceRoot=>"", :sources=>["bcdice/game_system/Aionia.rb"], :sourcesContent=>["# frozen_string_literal: true\n\nmodule BCDice\n  module GameSystem\n    class Aionia < Base\n      # ゲームシステムの識別子\n      ID = \"Aionia\"\n\n      # ゲームシステム名\n      NAME = \"慈悲なきアイオニア\"\n\n      # ゲームシステム名の読みがな\n      SORT_KEY = \"しひなきあいおにあ\"\n\n      HELP_MESSAGE = <<~INFO_MESSAGE_TEXT\n        - 技能判定（クリティカル・ファンブルなし）\n        AB{n}>={dif} n=10面ダイスの数、dif=難易度\n        - 技能判定（クリティカル・ファンブルあり）\n        ABT{n}>={dif} n=10面ダイスの数、dif=難易度\n\n        例:AB2>=5        （一般技能を活用して難易度5の技能判定。 クリファンなし。）\n        例:ABT3>=15      （専門技能を活用して難易度15の技能判定。クリファンあり。）\n        例:AB1+2>=8      （一般技能を活用せず難易度8の技能判定。 ボーナスとして+2点の補正あり。  クリファンなし。）\n        例:ABT3-3>=10    （専門技能を活用して難易度10の技能判定。ペナルティとして-3点の補正あり。クリファンあり。）\n        例:ABT2>=4/8/12  （一般技能を活用して難易度4/8/12の段階的な技能判定。クリファンあり。）\n      INFO_MESSAGE_TEXT\n\n      register_prefix('ABT?\\d+([\\+\\-]\\d+)?>=\\d+(\\/\\d+)*')\n\n      def eval_game_system_specific_command(command)\n        return roll_skills(command)\n      end\n\n      def roll_skills(command)\n        m = %r{AB(T?)(\\d+)([+-]\\d+)?>=((\\d+)((/\\d+)*))}.match(command)\n        return nil unless m\n\n        # 値の取得\n        use_cf = m[1] != ''\n        times = m[2].to_i\n        bonus = m[3].to_i\n        targets = m[4].split('/').map(&:to_i)\n        target = targets[0]\n        min_target = targets.min\n        max_target = targets.max\n\n        # ダイスロール\n        dice_list = @randomizer.roll_barabara(times, 10)\n        dice_total = dice_list.sum\n        total = dice_total + bonus\n\n        # Result用変数宣言\n        is_success = false\n        has_critical = false\n        has_fumble = false\n\n        # 結果判定\n        # 難易度が一つの場合\n        if targets.count == 1\n          if total >= target\n            is_success = true\n            if total >= target + 20 && use_cf\n              result = 'クリティカル'\n              has_critical = true\n            elsif target <= times\n              result = '自動成功'\n            else\n              result = '成功'\n            end\n          else\n            is_success = false\n            if dice_list.count(1) == times && use_cf\n              result = 'ファンブル'\n              has_fumble = true\n            elsif target > 10 * times\n              result = '自動失敗'\n            else\n              result = '失敗'\n            end\n          end\n        # 段階的な難易度判定の場合\n        else\n          if total >= min_target\n            is_success = true\n            if total >= max_target + 20 && use_cf\n              result = 'クリティカル'\n              has_critical = true\n            elsif max_target <= times\n              result = '自動成功'\n            elsif total >= max_target\n              result = '全成功'\n            else\n              times_suc = targets.count { |x| x <= total }\n              result = \"\#{times_suc}段階成功\"\n            end\n          else\n            is_success = false\n            if dice_list.count(1) == times && use_cf\n              result = 'ファンブル'\n              has_fumble = true\n            elsif min_target > 10 * times\n              result = '自動失敗'\n            else\n              result = '失敗'\n            end\n          end\n        end\n\n        # ボーナスがある場合の処理\n        bonus_text = ''\n        bonus_result = ''\n        if bonus != 0\n          if bonus > 0\n            bonus_text = \"+\"\n          end\n          bonus_text += bonus.to_s\n          bonus_result = \"\#{total} ＞ \"\n        end\n\n        # Resultクラスに結果を入れる\n        Result.new.tap do |r|\n          r.text = \"(\#{command}) ＞ \#{dice_total}[\#{dice_list.join(',')}]\#{bonus_text} ＞ \#{bonus_result}\#{result}\"\n          r.critical = has_critical\n          r.fumble = has_fumble\n          r.success = is_success\n          r.failure = !is_success\n        end\n      end\n    end\n  end\nend\n"], :names=>["<main>", "<module:BCDice>", "<module:GameSystem>", "<class:Aionia>", "self", "register_prefix", "eval_game_system_specific_command", "command", "roll_skills", "m", "match", "use_cf", "[]", "1", "!=", "times", "2", "to_i", "bonus", "3", "targets", "map", "4", "split", "to_proc", "target", "0", "min_target", "min", "max_target", "max", "dice_list", "@randomizer", "roll_barabara", "10", "dice_total", "sum", "total", "+", "is_success", "has_critical", "has_fumble", "count", ">=", "20", "result", "<=", ">", "*", "times_suc", "block in roll_skills", "x", "block (2 levels) in roll_skills", "bonus_text", "bonus_result", "to_s", "tap", "Result", "new", "r", "text=", "join", "critical=", "fumble=", "success=", "failure=", "!", "Base"], :mappings=>"AAAAA,2BAAAA;EAAAA;;EAEAA,OAAAC;EAAAA;;IAAAA;;IACEA,OAAAC;IAAAA;;MAAAA;;MACEA,OAAAC;MAAAA;;QAAAA;;AAAAA;;QAEE,8BAAKA,QAAL;QAGA,gCAAOA,WAAP;QAGA,oCAAWA,WAAX;QAEA,wCACNA,0BADqB,GAErBA,mCAFqB,GAGrBA,0BAHqB,GAIrBA,oCAJqB,GAKrBA,IALqB,GAMrBA,kDANqB,GAOrBA,kDAPqB,GAQrBA,oEARqB,GASrBA,mEATqB,GAUrBA,0DAVM;QAaAC,IAAAC,iBAAAA,CAAgBF,yCAAhBE;;AAEAC,QAAAA,iDAAAA,6CAAsCC,OAAtCD;AAAAA,UAAAA;;UACE,OAAOF,IAAAI,aAAAA,CAAYD,OAAZC;QADTF,CAAAA;QAIAH,OAAAK,2BAAAA,uBAAgBD,OAAhBC;AAAAA,UAAAA;;;UACEC,IAAI,0CAA2CC,OAAAA,CAAOH,OAAPG;UAC/C,KAAA,QAAkBD,CAAlB,CAAA;YAAA,OAAO;UAAP;UAGAE,SAASF,CAACG,OAAAA,CAACC,CAADD,CAAIE,OAAAA,CAAGN,EAAHM;UACdC,QAAQN,CAACG,OAAAA,CAACI,CAADJ,CAAGK,MAAAA,CAAAA;UACZC,QAAQT,CAACG,OAAAA,CAACO,CAADP,CAAGK,MAAAA,CAAAA;UACZG,UAAyBC,MAAfZ,CAACG,OAAAA,CAACU,CAADV,CAAGW,OAAAA,CAAOf,GAAPe,CAAWF,OAAAA,EAAAA,EAAAA,EAAM,MAADG,SAAAA,CAAAA,CAALH;UACzBI,SAASL,OAAOR,OAAAA,CAACc,CAADd;UAChBe,aAAaP,OAAOQ,KAAAA,CAAAA;UACpBC,aAAaT,OAAOU,KAAAA,CAAAA;UAGpBC,YAAYC,eAAWC,eAAAA,CAAelB,KAA1B,EAAiCmB,EAAtBD;UACvBE,aAAaJ,SAASK,KAAAA,CAAAA;UACtBC,QAAmBC,SAAXH,UAAWG,EAAEpB,KAAFoB;UAGnBC,aAAa;UACbC,eAAe;UACfC,aAAa;UAIb,IAAA,MAAGrB,OAAOsB,OAAAA,CAAAA,CAAV,EAAoB7B,CAApB,CAAA;YACE,IAAA,QAAS8B,OAANN,KAAMM,EAAGlB,MAAHkB,CAAT,CAAA;;cACEJ,aAAa;cACb,IAAG,CAAA,QAAMI,OAANN,KAAMM,EAAUL,SAAPb,MAAOa,EAAEM,EAAFN,CAAVK,CAAN,CAAA,IAAA,CAAA,Q